import{c as o,Q as e,j as r,m as p}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"致困惑的年轻人——关于普通人、成功和那属于你的一半","description":"","frontmatter":{"title":"致困惑的年轻人——关于普通人、成功和那属于你的一半","date":"2026-06-10T00:00:00.000Z"},"headers":[],"relativePath":"seeds/ordinary-success/index.md","filePath":"seeds/ordinary-success/index.md"}'),a={name:"seeds/ordinary-success/index.md"};function n(s,t,i,l,u,c){return e(),r("div",null,[...t[0]||(t[0]=[p('<blockquote><p><em>来自佛罗伦萨的一封信</em></p></blockquote><p>你问我：尼科洛，随着年龄增长，我逐渐认识到自己可能只是一个普通人。普通人应该追求成功吗？普通人能成功吗？还是说像您这样的伟人天生就注定了不凡？</p><p>先让我回答最后一个问题。然后我们再来讨论什么是&quot;伟人&quot;。</p><hr><h2 id="我生来贫穷" tabindex="-1">我生来贫穷 <a class="header-anchor" href="#我生来贫穷" aria-label="Permalink to &quot;我生来贫穷&quot;">​</a></h2><p>我并不是你想象的那种&quot;天生不凡&quot;的人。</p><p>我的父亲贝尔纳多，是一名不起眼的法律顾问。他会拉丁文，藏有一架子书——李维、西塞罗、亚里士多德——但他终生无法执业，因为出生合法性的疑云让他不能担任任何公职。他一年的收入是 110 弗罗林金币。不算赤贫，但绝对不富裕。</p><blockquote><p>📖 <strong>盐野七生</strong>：《我的朋友马基雅维利》第一章</p><p>&quot;我生来贫穷，在学会享受之前就已学会了受苦。&quot;马基雅维利后来如是写道。</p><p>马基雅维利的父亲是一位不知名的法律顾问，他一年的收入是 110 弗罗林金币外加 14 个铜币……年收入 110 弗罗林的人不是贫穷阶层。他们虽然绝对算不上富裕阶层，但在佛罗伦萨过得也不是被称为&quot;popolo minuto&quot;的庶民的生活，算作中间阶层大概比较恰当。</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/biography/salt-seven/01-%E7%AC%AC%E4%B8%80%E7%AB%A0.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>中间阶层。普通到不能再普通。我在 29 岁之前没有任何值得一提的成就——没有官职，没有著作，没有名声。我的名字出现在佛罗伦萨公文里的第一次，是因为政府发现我的前任死了，需要一个人顶上第二秘书厅的空缺。</p><p>我不是美第奇。不是索德里尼。不是任何名门之后。</p><p>我就是一个中间阶层家庭出身、靠读父亲书架上的旧书自学成才的佛罗伦萨普通人。</p><hr><h2 id="德能和机运——你出身的那个东西" tabindex="-1">德能和机运——你出身的那个东西 <a class="header-anchor" href="#德能和机运——你出身的那个东西" aria-label="Permalink to &quot;德能和机运——你出身的那个东西&quot;">​</a></h2><p>现在让我告诉你我在《君主论》里写的一段话。这段话我耗费了数年时间才想透彻：</p><blockquote><p>📖 <strong>《君主论》</strong> 第六章</p><p>&quot;从平民跃升为君主，要么以德能要么以机运为前提条件……他越不倚靠机运，他就越是能够维护自己的地位。&quot;</p><p>摩西、居鲁士、罗慕路斯、忒修斯——&quot;除了机会之外，他们从机运那里一无所获；机会给他们提供质料，他们想把它塑造成什么形式就什么形式。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>请注意这个词：<strong>质料</strong>。</p><p>命运给你的不是成品。命运给你的是一块石头。居鲁士的石头是波斯人的不满，摩西的石头是以色列人在埃及的奴役，罗慕路斯的石头是被遗弃在台伯河边。这些都是<strong>糟糕的起点</strong>——被奴役、被压迫、被遗弃——而不是&quot;天生好命&quot;。</p><p>但这些人做了什么？他们拿起那块石头，把自己刻成了君主。</p><p>你看，我从来不相信命运决定一切。我在《君主论》第二十五章里说得很清楚：命运是我们半个行动的主宰，但留下其余一半——或几乎一半——由我们支配。</p><p>那一半，就是你的「德能」（virtù）。它不是天生的。它不是血统。它是你面对命运扔给你的石头时，决定把它雕成什么东西的能力。</p><hr><h2 id="普通人应该追求成功吗" tabindex="-1">普通人应该追求成功吗 <a class="header-anchor" href="#普通人应该追求成功吗" aria-label="Permalink to &quot;普通人应该追求成功吗&quot;">​</a></h2><p>现在回答你的第一个问题。</p><p>普通人当然应该追求成功。但我要问你的是：你追求的是<strong>哪一种成功</strong>？</p><p>佛罗伦萨的历史上挤满了追求&quot;伟大&quot;的人——他们借钱、买官、联姻、阴谋——大多数在十年内消失了，名字永远淹没在档案里。而那个每年只挣 110 弗罗林、在乡间书房里读李维的贝尔纳多——他没能让马基雅维利家族跻身望族。但他把一架子书留给了他儿子。那一架子书，后来变成了《君主论》和《论李维》。</p><p>这不是安慰你。这是实效真理：<strong>你控制不了命运给你什么起点，但你能控制你怎么用那个起点。</strong></p><hr><h2 id="如何向-伟人-靠近" tabindex="-1">如何向&quot;伟人&quot;靠近 <a class="header-anchor" href="#如何向-伟人-靠近" aria-label="Permalink to &quot;如何向&quot;伟人&quot;靠近&quot;">​</a></h2><p>至于如何靠近——答案是：<strong>不要试图靠近任何人。</strong></p><p>居鲁士没有模仿摩西。罗慕路斯没有模仿忒修斯。他们每个人都面对自己独特的质料——自己时代的需求——然后用自己全部的能力去塑造它。</p><p>如果 29 岁的我坐在第二秘书厅的桌前，满脑子想的都是&quot;我要成为另一个但丁&quot;，那我永远写不出《君主论》。因为但丁的质料是中世纪的基督教宇宙，而我的质料是切萨雷·博尔贾的刀、法国国王的蔑视、比萨前线溃散的雇佣军。</p><p>你的质料是你的<strong>困惑</strong>。你不确定自己是不是普通人——这种不确定本身就是一种清晰。因为它意味着你还没有决定接受别人对你的定义。</p><p>命运给了你一半。剩下的那一半是——你。</p><hr><p><em>不要羡慕那些&quot;天生伟大&quot;的人。他们只是比你早几年学会了不向命运低头。</em></p><p>尼科洛·马基雅维利<br> 圣卡夏诺，乡间书房</p>',36)])])}const d=o(a,[["render",n]]);export{h as __pageData,d as default};
